namespace sv_2436340787c24655b850087a5fed5004.Services;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class NotificationItem
{
    public Guid Id { get; set; } = Guid.NewGuid();
    public string Title { get; set; } = string.Empty;
    public string Message { get; set; } = string.Empty;
    public Severity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; } = DateTime.UtcNow;
}

/// <summary>
/// Scoped per circuit. All subscribers are notified on every mutation
/// via the OnChange event.
/// </summary>
public class NotificationHub
{
    private readonly List<NotificationItem> _notifications = [];
    private readonly Lock _lock = new();

    /// <summary>
    /// Fired after every mutation. Subscribers on non-UI threads must
    /// marshal to InvokeAsync before calling StateHasChanged.
    /// </summary>
    public event Action? OnChange;

    public IReadOnlyList<NotificationItem> Notifications
    {
        get
        {
            lock (_lock) return _notifications.ToList();
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock) return _notifications.Count(n => !n.IsRead);
    }

    public void AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Add(new NotificationItem
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }
        OnChange?.Invoke();
    }

    public void MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var item = _notifications.FirstOrDefault(n => n.Id == id);
            if (item is not null) item.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications) n.IsRead = true;
        }
        OnChange?.Invoke();
    }

    public void DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }
        OnChange?.Invoke();
    }
}

namespace sv_2436340787c24655b850087a5fed5004.Services;

/// <summary>
/// Scoped per circuit. Started/stopped by the Dashboard page.
/// Adds a random notification every 15 seconds on a background thread,
/// which triggers NotificationHub.OnChange — subscribers must marshal
/// to InvokeAsync themselves.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private static readonly (string Title, string Message, Severity Severity)[] Templates =
    [
        ("Deployment complete", "Service v2.4.1 deployed to production.", Severity.Info),
        ("CPU spike detected", "Server us-east-1 CPU at 92% for 3 min.", Severity.Warning),
        ("Database failover", "Primary DB unreachable — failover activated.", Severity.Critical),
        ("New user sign-up", "user-7291 registered via OAuth.", Severity.Info),
        ("Disk usage warning", "Volume /data at 85% capacity.", Severity.Warning),
        ("SSL cert expiring", "Certificate for api.example.com expires in 7 days.", Severity.Critical),
        ("Build succeeded", "Pipeline #4821 passed all checks.", Severity.Info),
        ("Memory pressure", "Container web-app exceeded 1.8 GB RSS.", Severity.Warning),
    ];

    public SimulatorService(NotificationHub hub) => _hub = hub;

    public void Start()
    {
        if (_cts is not null) return; // already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            while (await _timer.WaitForNextTickAsync(token))
            {
                var template = Templates[Random.Shared.Next(Templates.Length)];
                _hub.AddNotification(template.Title, template.Message, template.Severity);
            }
        }, token);
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        _cts = null;
        _timer = null;
    }

    public void Dispose() => Stop();
}

