@* Interactive island — has its own render mode so it works inside the static layout. *@
@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable

<div class="notification-bell" title="Notifications">
    <a href="notifications" class="nav-bell-link">
        <span class="bell-icon">🔔</span>
        @if (_unreadCount > 0)
        {
            <span class="badge bg-danger badge-count">@_unreadCount</span>
        }
    </a>
</div>

@code {
    private int _unreadCount;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        // OnChange may fire from a background thread (SimulatorService timer),
        // so always marshal through InvokeAsync.
        _handler = () => InvokeAsync(() =>
        {
            _unreadCount = Hub.GetUnreadCount();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    public void Dispose() => Hub.OnChange -= _handler;
}

.notification-bell {
    position: relative;
    display: inline-block;
    padding: 0.4rem 0.6rem;
}

.nav-bell-link {
    color: #d7d7d7;
    text-decoration: none;
    font-size: 1.25rem;
    position: relative;
}

.nav-bell-link:hover {
    color: white;
}

.bell-icon {
    font-size: 1.3rem;
}

.badge-count {
    position: absolute;
    top: -0.4rem;
    right: -0.6rem;
    font-size: 0.65rem;
    padding: 0.2em 0.45em;
    border-radius: 50%;
}

@page "/notifications"
@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Notifications</h1>
    @if (Hub.Notifications.Any(n => !n.IsRead))
    {
        <button class="btn btn-outline-primary btn-sm" @onclick="Hub.MarkAllRead">
            Mark All Read
        </button>
    }
</div>

@if (!Hub.Notifications.Any())
{
    <p class="text-muted">No notifications yet.</p>
}
else
{
    @foreach (var group in Hub.Notifications
        .OrderByDescending(n => n.Severity)
        .ThenByDescending(n => n.Timestamp)
        .GroupBy(n => n.Severity))
    {
        <h4 class="mt-4">
            <span class="badge @SeverityBadgeClass(group.Key)">@group.Key</span>
        </h4>

        <ul class="list-group mb-3">
            @foreach (var n in group)
            {
                <li class="list-group-item d-flex justify-content-between align-items-start
                           @(n.IsRead ? "list-group-item-light" : "")">
                    <div class="ms-2 me-auto">
                        <div class="fw-bold">
                            @if (!n.IsRead) { <span class="text-primary">● </span> }
                            @n.Title
                        </div>
                        <small>@n.Message</small>
                        <br />
                        <small class="text-muted">@n.Timestamp.ToString("g")</small>
                    </div>
                    <div class="btn-group btn-group-sm ms-2">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success btn-sm"
                                    @onclick="() => Hub.MarkAsRead(n.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-outline-danger btn-sm"
                                @onclick="() => Hub.DismissNotification(n.Id)">
                            Dismiss
                        </button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Hub.OnChange += _handler;
    }

    public void Dispose() => Hub.OnChange -= _handler;

    private static string SeverityBadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning  => "bg-warning text-dark",
        _                 => "bg-info text-dark"
    };
}

